pub struct ServerJoinInformation {
    pub gathering_info: Option<Box<GatheringJoinInfo>>,
    pub store_entry_point_info: Option<StoreEntryPointInfo>,
    pub presence_info: Option<PresenceInfo>,
}
impl crate::bedrock::codec::BedrockSized for ServerJoinInformation {
    fn encoded_size(&self) -> usize {
        let mut size = 0usize;
        size += 1usize;
        size += match &self.gathering_info {
            Some(_v) => crate::bedrock::codec::BedrockSized::encoded_size(_v),
            None => 0usize,
        };
        size += {
            1usize
                + match &self.store_entry_point_info {
                    Some(_v) => crate::bedrock::codec::BedrockSized::encoded_size(_v),
                    None => 0usize,
                }
        };
        size += {
            1usize
                + match &self.presence_info {
                    Some(_v) => crate::bedrock::codec::BedrockSized::encoded_size(_v),
                    None => 0usize,
                }
        };
        size
    }
}
impl crate::bedrock::codec::BedrockCodec for ServerJoinInformation {
    type Args = ();
    fn encode<B: bytes::BufMut>(&self, buf: &mut B) -> Result<(), std::io::Error> {
        let _ = buf;
        let val = self.gathering_info.is_some();
        val.encode(buf)?;
        if let Some(v) = &self.gathering_info {
            v.encode(buf)?;
        }
        match &self.store_entry_point_info {
            Some(v) => {
                buf.put_u8(1);
                v.encode(buf)?;
            }
            None => buf.put_u8(0),
        }
        match &self.presence_info {
            Some(v) => {
                buf.put_u8(1);
                v.encode(buf)?;
            }
            None => buf.put_u8(0),
        }
        Ok(())
    }
    fn decode<B: bytes::Buf>(
        buf: &mut B,
        _args: Self::Args,
    ) -> Result<Self, crate::bedrock::error::DecodeError> {
        let _ = buf;
        let has_gathering_info = <bool as crate::bedrock::codec::BedrockCodec>::decode(buf, ())?;
        let gathering_info = if has_gathering_info {
            Some(Box::new(
                <GatheringJoinInfo as crate::bedrock::codec::BedrockCodec>::decode(buf, ())?,
            ))
        } else {
            None
        };
        let store_entry_point_info = {
            let present = u8::decode(buf, ())?;
            if present != 0 {
                Some(<StoreEntryPointInfo as crate::bedrock::codec::BedrockCodec>::decode(buf, ())?)
            } else {
                None
            }
        };
        let presence_info = {
            let present = u8::decode(buf, ())?;
            if present != 0 {
                Some(<PresenceInfo as crate::bedrock::codec::BedrockCodec>::decode(buf, ())?)
            } else {
                None
            }
        };
        Ok(Self {
            gathering_info,
            store_entry_point_info,
            presence_info,
        })
    }
}
