impl crate::bedrock::codec::BedrockSized for Transaction {
    fn encoded_size(&self) -> usize {
        let mut size = 0usize;
        size += crate::bedrock::codec::BedrockSized::encoded_size(&self.legacy);
        size += {
            1usize
                + match &self.transaction_type {
                    Some(_v) => crate::bedrock::codec::BedrockSized::encoded_size(_v),
                    None => 0usize,
                }
        };
        size += {
            1usize
                + match &self.actions {
                    Some(_v) => {
                        let _len = (_v).len();
                        crate::bedrock::codec::BedrockSized::encoded_size(
                            &crate::bedrock::codec::VarInt(_len as i32),
                        ) + (_v)
                            .iter()
                            .map(|_item| crate::bedrock::codec::BedrockSized::encoded_size(_item))
                            .sum::<usize>()
                    }
                    None => 0usize,
                }
        };
        size += match &self.transaction_data {
            Some(_v) => match _v {
                TransactionTransactionData::InventoryMismatch => 0usize,
                TransactionTransactionData::ItemRelease(_v) => {
                    crate::bedrock::codec::BedrockSized::encoded_size(_v)
                }
                TransactionTransactionData::ItemUse(_v) => {
                    crate::bedrock::codec::BedrockSized::encoded_size(_v)
                }
                TransactionTransactionData::ItemUseOnEntity(_v) => {
                    crate::bedrock::codec::BedrockSized::encoded_size(_v)
                }
                TransactionTransactionData::Normal => 0usize,
            },
            None => 0usize,
        };
        size
    }
}
impl crate::bedrock::codec::BedrockCodec for Transaction {
    type Args = TransactionArgs;
    fn encode<B: bytes::BufMut>(&self, buf: &mut B) -> Result<(), std::io::Error> {
        let _ = buf;
        self.legacy.encode(buf)?;
        match &self.transaction_type {
            Some(v) => {
                buf.put_u8(1);
                v.encode(buf)?;
            }
            None => buf.put_u8(0),
        }
        match &self.actions {
            Some(v) => {
                buf.put_u8(1);
                let len = v.len();
                crate::bedrock::codec::VarInt(len as i32).encode(buf)?;
                for item in v {
                    item.encode(buf)?;
                }
            }
            None => buf.put_u8(0),
        }
        if let Some(v) = &self.transaction_data {
            match v {
                TransactionTransactionData::InventoryMismatch => {}
                TransactionTransactionData::ItemRelease(v) => {
                    v.encode(buf)?;
                }
                TransactionTransactionData::ItemUse(v) => {
                    v.encode(buf)?;
                }
                TransactionTransactionData::ItemUseOnEntity(v) => {
                    v.encode(buf)?;
                }
                TransactionTransactionData::Normal => {}
            }
        }
        Ok(())
    }
    fn decode<B: bytes::Buf>(
        buf: &mut B,
        args: Self::Args,
    ) -> Result<Self, crate::bedrock::error::DecodeError> {
        let _ = buf;
        let legacy = <TransactionLegacy as crate::bedrock::codec::BedrockCodec>::decode(buf, ())?;
        let transaction_type = {
            let present = u8::decode(buf, ())?;
            if present != 0 {
                Some(
                    <TransactionTransactionType as crate::bedrock::codec::BedrockCodec>::decode(
                        buf,
                        (),
                    )?,
                )
            } else {
                None
            }
        };
        let actions = {
            let present = u8::decode(buf, ())?;
            if present != 0 {
                Some({
                    let res: TransactionActions = {
                        let raw = <crate::bedrock::codec::VarInt as crate::bedrock::codec::BedrockCodec>::decode(
                                buf,
                                (),
                            )?
                            .0 as i64;
                        if raw < 0 {
                            return Err(crate::bedrock::error::DecodeError::NegativeLength {
                                value: raw,
                            });
                        }
                        let len = raw as usize;
                        let mut tmp_vec = Vec::with_capacity(len);
                        for _ in 0..len {
                            tmp_vec
                                .push(
                                    <TransactionActionsItem as crate::bedrock::codec::BedrockCodec>::decode(
                                        buf,
                                        (),
                                    )?,
                                );
                        }
                        tmp_vec
                    };
                    res
                })
            } else {
                None
            }
        };
        let transaction_data = match transaction_type {
            Some(TransactionTransactionType::InventoryMismatch) => {
                Some(TransactionTransactionData::InventoryMismatch)
            }
            Some(TransactionTransactionType::ItemRelease) => {
                Some(
                    TransactionTransactionData::ItemRelease(
                        Box::new(
                            <TransactionTransactionDataItemRelease as crate::bedrock::codec::BedrockCodec>::decode(
                                buf,
                                (),
                            )?,
                        ),
                    ),
                )
            }
            Some(TransactionTransactionType::ItemUse) => {
                Some(
                    TransactionTransactionData::ItemUse(
                        Box::new(
                            <TransactionUseItem as crate::bedrock::codec::BedrockCodec>::decode(
                                buf,
                                TransactionUseItemArgs {
                                    shield_item_id: args.shield_item_id,
                                },
                            )?,
                        ),
                    ),
                )
            }
            Some(TransactionTransactionType::ItemUseOnEntity) => {
                Some(
                    TransactionTransactionData::ItemUseOnEntity(
                        Box::new(
                            <TransactionTransactionDataItemUseOnEntity as crate::bedrock::codec::BedrockCodec>::decode(
                                buf,
                                (),
                            )?,
                        ),
                    ),
                )
            }
            Some(TransactionTransactionType::Normal) => {
                Some(TransactionTransactionData::Normal)
            }
            _ => None,
        };
        Ok(Self {
            legacy,
            transaction_type,
            actions,
            transaction_data,
        })
    }
}
